Node n = *node3->next;
```

**GLOBAL FIX:** Use smart pointers (std::shared_ptr or std::unique_ptr) and/or optional types to prevent null pointer dereferences at compile-time or runtime. Additionally, encapsulate pointer access through methods that check for validity:

```cpp
#include <memory>
#include <optional>

class Node
{
public:
  int data;
  std::shared_ptr<Node> next;

  Node(int value) : data(value), next(nullptr) {}

  // Safe accessor that returns optional
  std::optional<std::reference_wrapper<Node>> getNext() {
    if (next) {
      return std::ref(*next);
    }
    return std::nullopt;
  }
};

// Usage:
int main() {
  auto node3 = std::make_shared<Node>(30);

  auto nextNode = node3->getNext();
  if (nextNode) {
    Node n = nextNode->get();
  } else {
    // Handle the null case explicitly
  }
}
```

Alternatively, use a reference-based API where cycles are represented differently, or use static analysis tools like clang-tidy with null-dereference checks enabled to catch these at compile time.

